text:
A rounding of less than 1 msec can cause division by zero in ZERODELAY.

  $ top -s 0

It also produces an artifact of extra zeros 000 in kernel_stats.
Perhaps, better to get rid of the rounding.

--- a.diff begins here ---
Index: usr.bin/top/machine.c
===================================================================
--- usr.bin/top/machine.c	(revision 222359)
+++ usr.bin/top/machine.c	(working copy)
@@ -1128,6 +1189,10 @@ get_system_info(struct system_info *si)
     timersub(&thistime, &lasttime, &timediff);
     elapsed_time = timediff.tv_sec * 1000000 + timediff.tv_usec;
     elapsed_msecs = timediff.tv_sec * 1000 + timediff.tv_usec / 1000;
+    if (elapsed_msecs == 0)
+    {
+	elapsed_msecs = 1;
+    }

     /* get the load averages */
     if (getloadavg(si->load_avg, NUM_AVERAGES) == -1)
--- a.diff ends here ---

